class DiskCache:
    """Disk-based cache with msgpack serialization and timestamp-based expiration."""

    def __init__(self, cache_dir="cache", default_ttl=300):
        self.cache_dir = cache_dir
        self.default_ttl = default_ttl
        self._lock = threading.Lock()
        os.makedirs(self.cache_dir, exist_ok=True)

    def _make_key(self, key_string):
        """Generate a safe filename from a cache key string."""
        return hashlib.sha256(key_string.encode("utf-8")).hexdigest()

    def _cache_path(self, hashed_key):
        """Return full path to the cache file."""
        return os.path.join(self.cache_dir, f"{hashed_key}.msgpack")

    def _serialize(self, data):
        """Serialize data using msgpack for fast binary serialization."""
        envelope = {
            "timestamp": time.time(),
            "data": data,
        }
        return msgpack.packb(envelope, use_bin_type=True)

    def _deserialize(self, raw_bytes):
        """Deserialize msgpack bytes back to Python objects."""
        return msgpack.unpackb(raw_bytes, raw=False)

    def get(self, key, ttl=None):
        """
        Retrieve a cached value by key.
        Returns None if not found or expired.
        """
        if ttl is None:
            ttl = self.default_ttl

        hashed_key = self._make_key(key)
        path = self._cache_path(hashed_key)

        with self._lock:
            if not os.path.exists(path):
                return None

            try:
                with open(path, "rb") as f:
                    raw = f.read()
                envelope = self._deserialize(raw)
            except (msgpack.UnpackException, IOError, KeyError):
                self._safe_remove(path)
                return None

            age = time.time() - envelope["timestamp"]
            if age > ttl:
                self._safe_remove(path)
                return None

            return envelope["data"]

    def set(self, key, data, ttl=None):
        """Store data in cache."""
        _ = ttl  # ttl is checked on read; stored timestamp enables flexible expiration
        hashed_key = self._make_key(key)
        path = self._cache_path(hashed_key)

        serialized = self._serialize(data)

        with self._lock:
            tmp_path = path + ".tmp"
            try:
                with open(tmp_path, "wb") as f:
                    f.write(serialized)
                os.replace(tmp_path, path)
            except IOError:
                self._safe_remove(tmp_path)
                raise

    def delete(self, key):
        """Remove a specific key from the cache."""
        hashed_key = self._make_key(key)
        path = self._cache_path(hashed_key)
        with self._lock:
            self._safe_remove(path)

    def clear(self):
        """Remove all cached entries."""
        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if filename.endswith(".msgpack"):
                    self._safe_remove(os.path.join(self.cache_dir, filename))

    def cleanup_expired(self, ttl=None):
        """Remove all expired entries from disk."""
        if ttl is None:
            ttl = self.default_ttl

        now = time.time()
        removed = 0

        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                path = os.path.join(self.cache_dir, filename)
                try:
                    with open(path, "rb") as f:
                        envelope = self._deserialize(f.read())
                    if now - envelope["timestamp"] > ttl:
                        self._safe_remove(path)
                        removed += 1
                except (msgpack.UnpackException, IOError, KeyError):
                    self._safe_remove(path)
                    removed += 1

        return removed

    def stats(self):
        """Return cache statistics."""
        total = 0
        expired = 0
        total_size = 0
        now = time.time()

        with self._lock:
            for filename in os.listdir(self.cache_dir):
                if not filename.endswith(".msgpack"):
                    continue
                path = os.path.join(self.cache_dir, filename)
                try:
                    total_size += os.path.getsize(path)
                    with open(path, "rb") as f:
                        envelope = self._deserialize(f.read())
                    total += 1
                    if now - envelope["timestamp"] > self.default_ttl:
                        expired += 1
                except (msgpack.UnpackException, IOError, KeyError):
                    pass

        return {
            "total_entries": total,
            "expired_entries": expired,
            "active_entries": total - expired,
            "total_size_bytes": total_size,
        }

    @staticmethod
    def _safe_remove(path):
        try:
            os.remove(path)
        except FileNotFoundError:
            pass


# Global cache instance
cache = DiskCache(cache_dir="api_cache", default_ttl=300)


def cached_route(ttl=None, key_func=None):
    """
    Decorator for Flask routes that caches the JSON response to disk.

    Args:
        ttl: Time-to-live in seconds (None uses cache default).
        key_func: Optional callable(request) -> str to build the cache key.
                  Defaults to method + full URL + sorted query string.
    """
    def decorator(f):
        @wraps(f)
        def wrapper(*args, **kwargs):
            if key_func:
                cache_key = key_func(request)
            else:
                cache_key = f"{request.method}:{request.url}:{sorted(request.args.items())}"

            cached_data = cache.get(cache_key, ttl=ttl)
            if cached_data is not None:
                response = jsonify(cached_data)
                response.headers["X-Cache"] = "HIT"
                return response

            result = f(*args, **kwargs)

            # Handle both raw dicts and Flask Response objects
            if isinstance(result, dict):
                cache.set(cache_key, result, ttl=ttl)
                response = jsonify(result)
            elif isinstance(result, tuple):
                data, status_code = result[0], result[1] if len(result) > 1 else 200
                if isinstance(data, dict) and (200 <= status_code < 300):
                    cache.set(cache_key, data, ttl=ttl)
                response = jsonify(data)
                response.status_code = status_code
            else:
                return result

            response.headers["X-Cache"] = "MISS"
            return response

        return wrapper
    return decorator


