@app.route("/api/cache/invalidate", methods=["POST"])
def cache_invalidate():
    """Invalidate a specific cache key by providing the original URL."""
    url = request.json.get("url") if request.json else None
    if not url:
        return jsonify({"error": "Provide 'url' in JSON body"}), 400

    # Reconstruct the cache key the same way cached_route does for GET requests
    from urllib.parse import urlparse, parse_qs
    parsed = urlparse(url)
    query_items = sorted(parse_qs(parsed.query, keep_blank_values=True).items())
    cache_key = f"GET:{url}:{query_items}"
    cache.delete(cache_key)
    return jsonify({"status": "invalidated", "key_source": url})


